package com.enterprise.app.repository;

import com.enterprise.app.entity.User;
import com.enterprise.app.entity.UserRole;
import com.enterprise.app.entity.UserStatus;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Lock;
import org.springframework.data.jpa.repository.Modifying;
import org.springframework.data.jpa.repository.Query;
import org.springframework.data.repository.query.Param;
import org.springframework.stereotype.Repository;

import jakarta.persistence.LockModeType;
import java.math.BigDecimal;
import java.util.List;
import java.util.Optional;

@Repository
public interface UserRepository extends JpaRepository<User, Long> {

    Optional<User> findByUsername(String username);

    Optional<User> findByEmail(String email);

    boolean existsByUsername(String username);

    boolean existsByEmail(String email);

    @Lock(LockModeType.PESSIMISTIC_WRITE)
    @Query("SELECT u FROM User u WHERE u.id = :id")
    Optional<User> findByIdWithLock(@Param("id") Long id);

    List<User> findByStatus(UserStatus status);

    List<User> findByRole(UserRole role);

    Page<User> findByStatus(UserStatus status, Pageable pageable);

    @Query("SELECT u FROM User u WHERE u.status = :status AND u.role = :role")
    List<User> findByStatusAndRole(@Param("status") UserStatus status, @Param("role") UserRole role);

    @Query("SELECT u FROM User u WHERE LOWER(u.firstName) LIKE LOWER(CONCAT('%', :name, '%')) " +
            "OR LOWER(u.lastName) LIKE LOWER(CONCAT('%', :name, '%')) " +
            "OR LOWER(u.username) LIKE LOWER(CONCAT('%', :name, '%'))")
    Page<User> searchByName(@Param("name") String name, Pageable pageable);

    @Modifying
    @Query("UPDATE User u SET u.balance = u.balance + :amount WHERE u.id = :userId")
    int updateBalance(@Param("userId") Long userId, @Param("amount") BigDecimal amount);

    @Modifying
    @Query("UPDATE User u SET u.status = :status WHERE u.id = :userId")
    int updateStatus(@Param("userId") Long userId, @Param("status") UserStatus status);

    @Query("SELECT u FROM User u WHERE u.balance >= :minBalance ORDER BY u.balance DESC")
    List<User> findUsersWithMinimumBalance(@Param("minBalance") BigDecimal minBalance);

    @Query(value = "SELECT COUNT(*) FROM users WHERE status = :status", nativeQuery = true)
    long countByStatusNative(@Param("status") String status);
}


// src/main/java/com/enterprise/app/repository/TransactionRepository.java
package com.enterprise.app.repository;

import com.enterprise.app.entity.Transaction;
import com.enterprise.app.entity.TransactionStatus;
import com.enterprise.app.entity.TransactionType;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import org.springframework.data.repository.query.Param;
import org.springframework.stereotype.Repository;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.List;
import java.util.Optional;

@Repository
public interface TransactionRepository extends JpaRepository<Transaction, Long> {

    Optional<Transaction> findByReferenceNumber(String referenceNumber);

    boolean existsByReferenceNumber(String referenceNumber);

    List<Transaction> findBySourceUserId(Long userId);

    List<Transaction> findByTargetUserId(Long userId);

    Page<Transaction> findBySourceUserIdOrTargetUserId(Long sourceUserId, Long targetUserId, Pageable pageable);

    List<Transaction> findByStatus(TransactionStatus status);

    List<Transaction> findByTransactionType(TransactionType transactionType);

    @Query("SELECT t FROM Transaction t WHERE t.sourceUser.id = :userId OR t.targetUser.id = :userId " +
            "ORDER BY t.createdAt DESC")
    Page<Transaction> findAllTransactionsByUserId(@Param("userId") Long userId, Pageable pageable);

    @Query("SELECT t FROM Transaction t WHERE t.createdAt BETWEEN :startDate AND :endDate " +
            "ORDER BY t.createdAt DESC")
    List<Transaction> findTransactionsBetweenDates(@Param("startDate") LocalDateTime startDate,
                                                    @Param("endDate") LocalDateTime endDate);

    @Query("SELECT t FROM Transaction t WHERE (t.sourceUser.id = :userId OR t.targetUser.id = :userId) " +
            "AND t.createdAt BETWEEN :startDate AND :endDate ORDER BY t.createdAt DESC")
    List<Transaction> findUserTransactionsBetweenDates(@Param("userId") Long userId,
                                                       @Param("startDate") LocalDateTime startDate,
                                                       @Param("endDate") LocalDateTime endDate);

    @Query("SELECT t FROM Transaction t WHERE t.status = :status AND t.transactionType = :type")
    List<Transaction> findByStatusAndType(@Param("status") TransactionStatus status,
                                          @Param("type") TransactionType type);

    @Query("SELECT SUM(t.amount) FROM Transaction t WHERE t.sourceUser.id = :userId " +
            "AND t.status = 'COMPLETED' AND t.transactionType = :type")
    BigDecimal sumCompletedAmountByUserAndType(@Param("userId") Long userId,
                                               @Param("type") TransactionType type);

    @Query("SELECT COUNT(t) FROM Transaction t WHERE t.sourceUser.id = :userId AND t.status = :status")
    long countBySourceUserAndStatus(@Param("userId") Long userId, @Param("status") TransactionStatus status);

    @Query("SELECT t FROM Transaction t WHERE t.status = 'PENDING' AND t.createdAt < :cutoffTime")
    List<Transaction> findStalePendingTransactions(@Param("cutoffTime") LocalDateTime cutoffTime);

    @Query(value = "SELECT transaction_type, COUNT(*), SUM(amount) FROM transactions " +
            "WHERE status = 'COMPLETED' AND created_at BETWEEN :startDate AND :endDate " +
            "GROUP BY transaction_type", nativeQuery = true)
    List<Object[]> getTransactionSummary(@Param("startDate") LocalDateTime startDate,
                                          @Param("endDate") LocalDateTime endDate);
}


