package com.enterprise.app.service.impl;

import com.enterprise.app.dto.UserDTO;
import com.enterprise.app.entity.User;
import com.enterprise.app.entity.UserRole;
import com.enterprise.app.entity.UserStatus;
import com.enterprise.app.exception.DuplicateResourceException;
import com.enterprise.app.exception.InsufficientBalanceException;
import com.enterprise.app.exception.ResourceNotFoundException;
import com.enterprise.app.repository.UserRepository;
import com.enterprise.app.service.UserService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.util.List;
import java.util.stream.Collectors;

@Service
@Transactional
public class UserServiceImpl implements UserService {

    private static final Logger logger = LoggerFactory.getLogger(UserServiceImpl.class);

    private final UserRepository userRepository;

    public UserServiceImpl(UserRepository userRepository) {
        this.userRepository = userRepository;
    }

    @Override
    public UserDTO createUser(UserDTO userDTO) {
        logger.info("Creating new user with username: {}", userDTO.getUsername());

        if (userRepository.existsByUsername(userDTO.getUsername())) {
            throw new DuplicateResourceException("Username '" + userDTO.getUsername() + "' already exists");
        }
        if (userRepository.existsByEmail(userDTO.getEmail())) {
            throw new DuplicateResourceException("Email '" + userDTO.getEmail() + "' already exists");
        }

        User user = mapToEntity(userDTO);
        user.setBalance(BigDecimal.ZERO);
        user.setStatus(UserStatus.ACTIVE);
        user.setRole(UserRole.USER);

        User savedUser = userRepository.save(user);
        logger.info("User created successfully with ID: {}", savedUser.getId());
        return mapToDTO(savedUser);
    }

    @Override
    @Transactional(readOnly = true)
    public UserDTO getUserById(Long id) {
        User user = userRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("User", "id", id));
        return mapToDTO(user);
    }

    @Override
    @Transactional(readOnly = true)
    public UserDTO getUserByUsername(String username) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new ResourceNotFoundException("User", "username", username));
        return mapToDTO(user);
    }

    @Override
    @Transactional(readOnly = true)
    public UserDTO getUserByEmail(String email) {
        User user = userRepository.findByEmail(email)
                .orElseThrow(() -> new ResourceNotFoundException("User", "email", email));
        return mapToDTO(user);
    }

    @Override
    @Transactional(readOnly = true)
    public Page<UserDTO> getAllUsers(Pageable pageable) {
        return userRepository.findAll(pageable).map(this::mapToDTO);
    }

    @Override
    @Transactional(readOnly = true)
    public Page<UserDTO> getUsersByStatus(UserStatus status, Pageable pageable) {
        return userRepository.findByStatus(status, pageable).map(this::mapToDTO);
    }

    @Override
    @Transactional(readOnly = true)
    public Page<UserDTO> searchUsers(String name, Pageable pageable) {
        return userRepository.searchByName(name, pageable).map(this::mapToDTO);
    }

    @Override
    public UserDTO updateUser(Long id, UserDTO userDTO) {
        logger.info("Updating user with ID: {}", id);

        User existingUser = userRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("User", "id", id));

        if (userDTO.getUsername() != null && !userDTO.getUsername().equals(existingUser.getUsername())) {
            if (userRepository.existsByUsername(userDTO.getUsername())) {
                throw new DuplicateResourceException("Username '" + userDTO.getUsername() + "' already exists");
            }
            existingUser.setUsername(userDTO.getUsername());
        }

        if (userDTO.getEmail() != null && !userDTO.getEmail().equals(existingUser.getEmail())) {
            if (userRepository.existsByEmail(userDTO.getEmail())) {
                throw new DuplicateResourceException("Email '" + userDTO.getEmail() + "' already exists");
            }
            existingUser.setEmail(userDTO.getEmail());
        }

        if (userDTO.getFirstName() != null) existingUser.setFirstName(userDTO.getFirstName());
        if (userDTO.getLastName() != null) existingUser.setLastName(userDTO.getLastName());
        if (userDTO.getPhone() != null) existingUser.setPhone(userDTO.getPhone());
        if (userDTO.getPassword() != null) existingUser.setPassword(userDTO.getPassword());

        User updatedUser = userRepository.save(existingUser);
        logger.info("User updated successfully with ID: {}", updatedUser.getId());
        return mapToDTO(updatedUser);
    }

    @Override
    public void deleteUser(Long id) {
        logger.info("Deleting user with ID: {}", id);
        User user = userRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("User", "id", id));
        user.setStatus(UserStatus.DELETED);
        userRepository.save(user);
        logger.info("User soft-deleted successfully with ID: {}", id);
    }

    @Override
    public void updateUserStatus(Long id, UserStatus status) {
        logger.info("Updating status to {} for user ID: {}", status, id);
        int updated = userRepository.updateStatus(id, status);
        if (updated == 0) {
            throw new ResourceNotFoundException("User", "id", id);
        }
    }

    @Override
    public void updateUserRole(Long id, UserRole role) {
        logger.info("Updating role to {} for user ID: {}", role, id);
        User user = userRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("User", "id", id));
        user.setRole(role);
        userRepository.save(user);
    }

    @Override
    public UserDTO depositBalance(Long userId, BigDecimal amount) {
        logger.info("Depositing {} to user ID: {}", amount, userId);
        User user = userRepository.findByIdWithLock(userId)
                .orElseThrow(() -> new ResourceNotFoundException("User", "id", userId));
        user.setBalance(user.getBalance().add(amount));
        User updatedUser = userRepository.save(user);
        return mapToDTO(updatedUser);
    }

    @Override
    public UserDTO withdrawBalance(Long userId, BigDecimal amount) {
        logger.info("Withdrawing {} from user ID: {}", amount, userId);
        User user = userRepository.findByIdWithLock(userId)
                .orElseThrow(() -> new ResourceNotFoundException("User", "id", userId));

        if (user.getBalance().compareTo(amount) < 0) {
            throw new InsufficientBalanceException(
                    "Insufficient balance. Available: " + user.getBalance() + ", Requested: " + amount);
        }

        user.setBalance(user.getBalance().subtract(amount));
        User updatedUser = userRepository.save(user);
        return mapToDTO(updatedUser);
    }

    @Override
    @Transactional(readOnly = true)
    public List<UserDTO> getUsersByRole(UserRole role) {
        return userRepository.findByRole(role).stream()
                .map(this::mapToDTO)
                .collect(Collectors.toList());
    }

    @Override
    @Transactional(readOnly = true)
    public long countUsersByStatus(UserStatus status) {
        return userRepository.countByStatusNative(status.name());
    }

    private UserDTO mapToDTO(User user) {
        UserDTO dto = new UserDTO();
        dto.setId(user.getId());
        dto.setUsername(user.getUsername());
        dto.setEmail(user.getEmail());
        dto.setFirstName(user.getFirstName());
        dto.setLastName(user.getLastName());
        dto.setPhone(user.getPhone());
        dto.setBalance(user.getBalance());
        dto.setStatus(user.getStatus().name());
        dto.setRole(user.getRole().name());
        return dto;
    }

    private User mapToEntity(UserDTO dto) {
        User user = new User();
        user.setUsername(dto.getUsername());
        user.setEmail(dto.getEmail());
        user.setPassword(dto.getPassword());
        user.setFirstName(dto.getFirstName());
        user.setLastName(dto.getLastName());
        user.setPhone(dto.getPhone());
        return user;
    }
}


// src/main/java/com/enterprise/app/service/impl/TransactionServiceImpl.java
package com.enterprise.app.service.impl;

import com.enterprise.app.dto.TransactionDTO;
import com.enterprise.app.dto.TransferRequestDTO;
import com.enterprise.app.entity.*;
import com.enterprise.app.exception.InsufficientBalanceException;
import com.enterprise.app.exception.ResourceNotFoundException;
import com.enterprise.app.exception.TransactionProcessingException;
import com.enterprise.app.repository.TransactionRepository;
import com.enterprise.app.repository.UserRepository;
import com.enterprise.app.service.TransactionService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Isolation;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.List;
import java.util.UUID;
import java.util.stream.Collectors;

@Service
@Transactional
public class TransactionServiceImpl implements TransactionService {

    private static final Logger logger = LoggerFactory.getLogger(TransactionServiceImpl.class);
    private static final BigDecimal TRANSFER_FEE_PERCENTAGE = new BigDecimal("0.001"); // 0.1%

    private final TransactionRepository transactionRepository;
    private final UserRepository userRepository;

    public TransactionServiceImpl(TransactionRepository transactionRepository, UserRepository userRepository) {
        this.transactionRepository = transactionRepository;
        this.userRepository = userRepository;
    }

    @Override
    @Transactional(isolation = Isolation.SERIALIZABLE)
    public TransactionDTO processTransfer(TransferRequestDTO transferRequest) {
        logger.info("Processing transfer from user {} to user {} for amount {}",
                transferRequest.getSourceUserId(), transferRequest.getTargetUserId(), transferRequest.getAmount());

        if (transferRequest.getSourceUserId().equals(transferRequest.getTargetUserId())) {
            throw new TransactionProcessingException("Cannot transfer to the same account");
        }

        // Lock users in consistent order to prevent deadlocks
        Long firstId = Math.min(transferRequest.getSourceUserId(), transferRequest.getTargetUserId());
        Long secondId = Math.max(transferRequest.getSourceUserId(), transferRequest.getTargetUserId());

        User firstUser = userRepository.findByIdWithLock(firstId)
                .orElseThrow(() -> new ResourceNotFoundException("User", "id", firstId));
        User secondUser = userRepository.findByIdWithLock(secondId)
                .orElseThrow(() -> new ResourceNotFoundException("User", "id", secondId));

        User sourceUser = firstId.equals(transferRequest.getSourceUserId()) ? firstUser : secondUser;
        User targetUser = firstId.equals(transferRequest.getTargetUserId()) ? firstUser : secondUser;

        if (sourceUser.getStatus() != UserStatus.ACTIVE) {
            throw new TransactionProcessingException("Source user account is not active");
        }
        if (targetUser.getStatus() != UserStatus.ACTIVE) {
            throw new TransactionProcessingException("Target user account is not active");
        }

        BigDecimal fee = transferRequest.getAmount().multiply(TRANSFER_FEE_PERCENTAGE);
        BigDecimal totalDeduction = transferRequest.getAmount().add(fee);

        if (sourceUser.getBalance().compareTo(totalDeduction) < 0) {
            throw new InsufficientBalanceException(
                    "Insufficient balance. Available: " + sourceUser.getBalance() +
                            ", Required: " + totalDeduction + " (including fee: " + fee + ")");
        }

        // Create transaction record
        Transaction transaction = new Transaction();
        transaction.setReferenceNumber(generateReferenceNumber());
        transaction.setAmount(transferRequest.getAmount());
        transaction.setFee(fee);
        transaction.setTransactionType(TransactionType.TRANSFER);
        transaction.setStatus(TransactionStatus.PROCESSING);
        transaction.setDescription(transferRequest.getDescription());
        transaction.setCurrency(transferRequest.getCurrency() != null ? transferRequest.getCurrency() : "USD");
        transaction.setSourceUser(sourceUser);
        transaction.setTargetUser(targetUser);

        try {
            // Execute transfer
            sourceUser.setBalance(sourceUser.getBalance().subtract(totalDeduction));
            targetUser.setBalance(targetUser.getBalance().add(transferRequest.getAmount()));

            userRepository.save(sourceUser);
            userRepository.save(targetUser);

            transaction.setStatus(TransactionStatus.COMPLETED);
            transaction.setProcessedAt(LocalDateTime.now());

            Transaction savedTransaction = transactionRepository.save(transaction);
            logger.info("Transfer completed successfully. Reference: {}", savedTransaction.getReferenceNumber());
            return mapToDTO(savedTransaction);

        } catch (Exception e) {
            transaction.setStatus(TransactionStatus.FAILED);
            transaction.setFailureReason(e.getMessage());
            transactionRepository.save(transaction);
            throw new TransactionProcessingException("Transfer failed: " + e.getMessage(), e);
        }
    }

    @Override
    @Transactional(isolation = Isolation.SERIALIZABLE)
    public TransactionDTO processDeposit(Long userId, BigDecimal amount, String description) {
        logger.info("Processing deposit of {} for user {}", amount, userId);

        User user = userRepository.findByIdWithLock(userId)
                .orElseThrow(() -> new ResourceNotFoundException("User", "id", userId));

        if (user.getStatus() != UserStatus.ACTIVE) {
            throw new TransactionProcessingException("User account is not active");
        }

        Transaction transaction = new Transaction();
        transaction.setReferenceNumber(generateReferenceNumber());
        transaction.setAmount(amount);
        transaction.setFee(BigDecimal.ZERO);
        transaction.setTransactionType(TransactionType.DEPOSIT);
        transaction.setStatus(TransactionStatus.PROCESSING);
        transaction.setDescription(description);
        transaction.setCurrency("USD");
        transaction.setSourceUser(user);

        try {
            user.setBalance(user.getBalance().add(amount));
            userRepository.save(user);

            transaction.setStatus(TransactionStatus.COMPLETED);
            transaction.setProcessedAt(LocalDateTime.now());
            Transaction savedTransaction = transactionRepository.save(transaction);

            logger.info("Deposit completed. Reference: {}", savedTransaction.getReferenceNumber());
            return mapToDTO(savedTransaction);

        } catch (Exception e) {
            transaction.setStatus(TransactionStatus.FAILED);
            transaction.setFailureReason(e.getMessage());
            transactionRepository.save(transaction);
            throw new TransactionProcessingException("Deposit failed: " + e.getMessage(), e);
        }
    }

    @Override
    @Transactional(isolation = Isolation.SERIALIZABLE)
    public TransactionDTO processWithdrawal(Long userId, BigDecimal amount, String description) {
        logger.info("Processing withdrawal of {} for user {}", amount, userId);

        User user = userRepository.findByIdWithLock(userId)
                .orElseThrow(() -> new ResourceNotFoundException("User", "id", userId));

        if (user.getStatus() != UserStatus.ACTIVE) {
            throw new TransactionProcessingException("User account is not active");
        }

        if (user.getBalance().compareTo(amount) < 0) {
            throw new InsufficientBalanceException(
                    "Insufficient balance. Available: " + user.getBalance() + ", Requested: " + amount);
        }

        Transaction transaction = new Transaction();
        transaction.setReferenceNumber(generateReferenceNumber());
        transaction.setAmount(amount);
        transaction.setFee(BigDecimal.ZERO);
        transaction.setTransactionType(TransactionType.WITHDRAWAL);
        transaction.setStatus(TransactionStatus.PROCESSING);
        transaction.setDescription(description);
        transaction.setCurrency("USD");
        transaction.setSourceUser(user);

        try {
            user.setBalance(user.getBalance().subtract(amount));
            userRepository.save(user);

            transaction.setStatus(TransactionStatus.COMPLETED);
            transaction.setProcessedAt(LocalDateTime.now());
            Transaction savedTransaction = transactionRepository.save(transaction);

            logger.info("Withdrawal completed. Reference: {}", savedTransaction.getReferenceNumber());
            return mapToDTO(savedTransaction);

        } catch (Exception e) {
            transaction.setStatus(TransactionStatus.FAILED);
            transaction.setFailureReason(e.getMessage());
            transactionRepository.save(transaction);
            throw new TransactionProcessingException("Withdrawal failed: " + e.getMessage(), e);
        }
    }

    @Override
    @Transactional(readOnly = true)
    public TransactionDTO getTransactionById(Long id) {
        Transaction transaction = transactionRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("Transaction", "id", id));
        return mapToDTO(transaction);
    }

    @Override
    @Transactional(readOnly = true)
    public TransactionDTO getTransactionByReference(String referenceNumber) {
        Transaction transaction = transactionRepository.findByReferenceNumber(referenceNumber)
                .orElseThrow(() -> new ResourceNotFoundException("Transaction", "referenceNumber", referenceNumber));
        return mapToDTO(transaction);
    }

    @Override
    @Transactional(readOnly = true)
    public Page<TransactionDTO> getUserTransactions(Long userId, Pageable pageable) {
        return transactionRepository.findAllTransactionsByUserId(userId, pageable).map(this::mapToDTO);
    }

    @Override
    @Transactional(readOnly = true)
    public List<TransactionDTO> getTransactionsByDateRange(LocalDateTime startDate, LocalDateTime endDate) {
        return transactionRepository.findTransactionsBetweenDates(startDate, endDate)
                .stream().map(this::mapToDTO).collect(Collectors.toList());
    }

    @Override
    @Transactional(readOnly = true)
    public List<TransactionDTO> getUserTransactionsByDateRange(Long userId, LocalDateTime startDate, LocalDateTime endDate) {
        return transactionRepository.findUserTransactionsBetweenDates(userId, startDate, endDate)
                .stream().map(this::mapToDTO).collect(Collectors.toList());
    }

    @Override
    public TransactionDTO cancelTransaction(Long transactionId) {
        logger.info("Cancelling transaction with ID: {}", transactionId);

        Transaction transaction = transactionRepository.findById(transactionId)
                .orElseThrow(() -> new ResourceNotFoundException("Transaction", "id", transactionId));

        if (transaction.getStatus() != TransactionStatus.PENDING) {
            throw new TransactionProcessingException(
                    "Only pending transactions can be cancelled. Current status: " + transaction.getStatus());
        }

        transaction.setStatus(TransactionStatus.CANCELLED);
        Transaction savedTransaction = transactionRepository.save(transaction);
        return mapToDTO(savedTransaction);
    }

    @Override
    @Transactional(readOnly = true)
    public List<TransactionDTO> getTransactionsByStatus(TransactionStatus status) {
        return transactionRepository.findByStatus(status)
                .stream().map(this::mapToDTO).collect(Collectors.toList());
    }

    @Override
    @Transactional(readOnly = true)
    public BigDecimal getUserTotalByType(Long userId, TransactionType type) {
        BigDecimal total = transactionRepository.sumCompletedAmountByUserAndType(userId, type);
        return total != null ? total : BigDecimal.ZERO;
    }

    @Override
    public void processStaleTransactions(int timeoutMinutes) {
        logger.info("Processing stale pending transactions older than {} minutes", timeoutMinutes);
        LocalDateTime cutoffTime = LocalDateTime.now().minusMinutes(timeoutMinutes);
        List<Transaction> staleTransactions = transactionRepository.findStalePendingTransactions(cutoffTime);

        for (Transaction transaction : staleTransactions) {
            transaction.setStatus(TransactionStatus.FAILED);
            transaction.setFailureReason("Transaction timed out after " + timeoutMinutes + " minutes");
            transactionRepository.save(transaction);
            logger.warn("Transaction {} marked as failed due to timeout", transaction.getReferenceNumber());
        }
    }

    private String generateReferenceNumber() {
        String reference;
        do {
            reference = "TXN-" + UUID.randomUUID().toString().replace("-", "").substring(0, 16).toUpperCase();
        } while (transactionRepository.existsByReferenceNumber(reference));
        return reference;
    }

    private TransactionDTO mapToDTO(Transaction transaction) {
        TransactionDTO dto = new TransactionDTO();
        dto.setId(transaction.getId());
        dto.setReferenceNumber(transaction.getReferenceNumber());
        dto.setAmount(transaction.getAmount());
        dto.setFee(transaction.getFee());
        dto.setTransactionType(transaction.getTransactionType().name());
        dto.setStatus(transaction.getStatus().name());
        dto.setDescription(transaction.getDescription());
        dto.setCurrency(transaction.getCurrency());
        dto.setSourceUserId(transaction.getSourceUser() != null ? transaction.getSourceUser().getId() : null);
        dto.setTargetUserId(transaction.getTargetUser() != null ? transaction.getTargetUser().getId() : null);
        dto.setProcessedAt(transaction.getProcessedAt() != null ? transaction.getProcessedAt().toString() : null);
        dto.setFailureReason(transaction.getFailureReason());
        dto.setCreatedAt(transaction.getCreatedAt() != null ? transaction.getCreatedAt().toString() : null);
        return dto;
    }
}


